'use strict';

const express = require('express');

const DEFAULT_HEADERS = {
  'X-Content-Type-Options': 'nosniff',
  'X-Frame-Options': 'DENY',
  'Referrer-Policy': 'no-referrer',
  'X-XSS-Protection': '0',
  'Cross-Origin-Opener-Policy': 'same-origin',
  'Cross-Origin-Resource-Policy': 'same-origin'
};

function setSecurityHeaders(set) {
  for (const [k, v] of Object.entries(DEFAULT_HEADERS)) {
    set(k, v);
  }
  if (process.env.FORTRESS_HSTS === 'true') {
    set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  }
}

function middleware(req, res, next) {
  setSecurityHeaders((k, v) => res.setHeader(k, v));
  next();
}

async function koaMiddleware(ctx, next) {
  setSecurityHeaders((k, v) => ctx.set(k, v));
  await next();
}

const router = express.Router();
router.get('/status/fo', (req, res) => {
  res.json({ status: 'ok', fortress: true });
});

module.exports = { middleware, koaMiddleware, router };

